1. Create Hook at apps/client/src/layers/entities/agent/model/use-agent-tool-status.ts:

import { useMemo } from 'react';
import { useCurrentAgent } from './use-current-agent';
import { useRelayEnabled } from '@/layers/entities/relay';
import { usePulseEnabled } from '@/layers/entities/pulse';

export type ChipState = 'enabled' | 'disabled-by-agent' | 'disabled-by-server';

export interface AgentToolStatus {
  pulse: ChipState;
  relay: ChipState;
  mesh: ChipState;
  adapter: ChipState;
}

export function useAgentToolStatus(projectPath: string): AgentToolStatus {
  const { data: agent } = useCurrentAgent(projectPath);
  const relayEnabled = useRelayEnabled();
  const pulseEnabled = usePulseEnabled();

  return useMemo(() => {
    const groups = agent?.enabledToolGroups ?? {};
    return {
      pulse: !pulseEnabled ? 'disabled-by-server'
        : groups.pulse === false ? 'disabled-by-agent' : 'enabled',
      relay: !relayEnabled ? 'disabled-by-server'
        : groups.relay === false ? 'disabled-by-agent' : 'enabled',
      mesh: groups.mesh === false ? 'disabled-by-agent' : 'enabled',
      adapter: !relayEnabled ? 'disabled-by-server'
        : groups.adapter === false ? 'disabled-by-agent' : 'enabled',
    };
  }, [agent, relayEnabled, pulseEnabled]);
}

